mapper.select:
SELECT

FROM gift a

WHERE a.id = #{id}

SELECT

FROM gift a


    a.del_flag = #{DEL_FLAG_NORMAL}

        AND a.name LIKE CONCAT('%', #{name}, '%')


        AND a.status = #{status}


        AND a.type = #{type}


ORDER BY a.`value` ASC, a.create_date DESC

